mapper.select:
SELECT

FROM subject_info t0

  t0.is_deleted = 0

    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.id = #{request.id}


    AND t0.tenant_id = #{request.tenantId}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.subject_name LIKE CONCAT('%',#{request.subjectName},'%')


    AND t0.nature = #{request.nature}


    AND t0.subject_type = #{request.subjectType}


    AND t0.document_type = #{request.documentType}


    AND t0.document_number LIKE CONCAT('%',#{request.documentNumber},'%')


    AND t0.legal_representative LIKE CONCAT('%',#{request.legalRepresentative},'%')


    AND t0.contacts LIKE CONCAT('%',#{request.contacts},'%')


    AND t0.phone LIKE CONCAT('%',#{request.phone},'%')


    AND t0.belong_province = #{request.belongProvince}


    AND t0.belong_city = #{request.belongCity}


    AND t0.belong_district = #{request.belongDistrict}


    AND t0.address = #{request.address}


    AND t0.remark = #{request.remark}


    AND t0.is_deleted = #{request.isDeleted}




    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
